function rowToAccount(r) {
  if (!r) return null;
  return { accountId: r.account_id, name: r.name, tier: r.tier, status: r.status, preferredPaymentMethod: r.preferred_payment_method ?? null };
}

export async function createAccount(client, data) {
  await ensureSchema(client);
  const createdAt = data.createdAt ?? new Date();
  if (data.preferredPaymentMethod !== undefined) {
    const res = await client.query(
      'INSERT INTO accounts (account_id, name, tier, status, preferred_payment_method, created_at) VALUES ($1, $2, $3, $4, $5, $6) RETURNING *',
      [data.accountId, data.name, data.tier, data.status, data.preferredPaymentMethod, createdAt]
    );
    return rowToAccount(res.rows[0]);
  }
  const res = await client.query(
    'INSERT INTO accounts (account_id, name, tier, status, created_at) VALUES ($1, $2, $3, $4, $5) RETURNING *',
    [data.accountId, data.name, data.tier, data.status, createdAt]
  );
  return rowToAccount(res.rows[0]);
}

export async function getAccount(client, accountId) {
  const res = await client.query('SELECT * FROM accounts WHERE account_id = $1', [accountId]);
  return rowToAccount(res.rows[0]);
}

export async function updateAccount(client, accountId, data) {
  const sets = [], vals = [];
  let i = 1;
  if (data.name !== undefined) { sets.push(`name = $${i++}`); vals.push(data.name); }
  if (data.tier !== undefined) { sets.push(`tier = $${i++}`); vals.push(data.tier); }
  if (data.status !== undefined) { sets.push(`status = $${i++}`); vals.push(data.status); }
  if (data.preferredPaymentMethod !== undefined) { sets.push(`preferred_payment_method = $${i++}`); vals.push(data.preferredPaymentMethod); }
  if (sets.length === 0) return getAccount(client, accountId);
  vals.push(accountId);
  await client.query(`UPDATE accounts SET ${sets.join(', ')} WHERE account_id = $${i}`, vals);
  const res = await client.query('SELECT * FROM accounts WHERE account_id = $1', [accountId]);
  return rowToAccount(res.rows[0]);
}

